import{_ as t,o as e,i as o,aB as c}from"./chunks/framework._ZAOES46.js";const u=JSON.parse('{"title":"FaTable 表格","description":"","frontmatter":{},"headers":[],"relativePath":"components/basic/FaTable.md","filePath":"components/basic/FaTable.md"}'),a={name:"components/basic/FaTable.md"};function r(l,d,s,n,i,b){return e(),o("div",null,[...d[0]||(d[0]=[c('<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /components/basic/FaTable.md for this page in Markdown format</div><h1 id="fatable-表格" tabindex="-1">FaTable 表格 <a class="header-anchor" href="#fatable-表格" aria-label="Permalink to “FaTable 表格”">​</a></h1><p>基于 TanStack Table 封装的数据表格组件，提供基础展示、树型数据、工具栏、列显示控制、排序、边框、斑马纹、固定列、固定高度、单选、多选和插槽自定义能力。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>常规数据列表展示</li><li>通过 <code>children</code> 或 <code>getSubRows</code> 展示树型层级数据</li><li>需要单选或多选的数据表格</li><li>固定列、固定高度等复杂表格布局</li><li>需要外部处理排序状态的数据表格</li><li>通过工具栏插槽放置新增、刷新、批量操作等自定义功能</li><li>通过插槽自定义单元格、表头、表尾和空状态</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to “Props”">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>columns</code></td><td><code>TableColumn[]</code></td><td><strong>必需</strong></td><td>表格列配置</td></tr><tr><td><code>data</code></td><td><code>TData[]</code></td><td><strong>必需</strong></td><td>表格数据</td></tr><tr><td><code>border</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否显示外边框和单元格纵向分割线</td></tr><tr><td><code>caption</code></td><td><code>string</code></td><td>-</td><td>表格标题</td></tr><tr><td><code>columnVisibility</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否在工具栏右侧显示列显示控制按钮</td></tr><tr><td><code>defaultSorting</code></td><td><code>TableSortingState</code></td><td><code>[]</code></td><td>初始排序状态，仅在未受控时生效</td></tr><tr><td><code>defaultExpanded</code></td><td><code>TableExpandedState</code></td><td><code>{}</code></td><td>初始展开状态，仅在未受控时生效</td></tr><tr><td><code>emptyText</code></td><td><code>string</code></td><td><code>&#39;暂无数据&#39;</code></td><td>空数据文本</td></tr><tr><td><code>enableMultiSort</code></td><td><code>boolean</code></td><td><code>true</code></td><td>是否允许多列排序</td></tr><tr><td><code>enableSortingRemoval</code></td><td><code>boolean</code></td><td><code>true</code></td><td>是否允许清除排序</td></tr><tr><td><code>expanded</code></td><td><code>TableExpandedState</code></td><td>-</td><td>受控展开状态</td></tr><tr><td><code>getRowId</code></td><td><code>TableOptions&lt;TData&gt;[&#39;getRowId&#39;]</code></td><td>-</td><td>自定义行 ID 获取方法</td></tr><tr><td><code>getSubRows</code></td><td><code>TableOptions&lt;TData&gt;[&#39;getSubRows&#39;]</code></td><td>-</td><td>自定义子行获取方法，未设置时默认读取 <code>children</code></td></tr><tr><td><code>indentSize</code></td><td><code>number</code></td><td><code>20</code></td><td>树型数据每一级缩进像素</td></tr><tr><td><code>manualExpanding</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否由外部手动处理展开数据</td></tr><tr><td><code>multiple</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否为多选模式</td></tr><tr><td><code>rowKey</code></td><td><code>keyof TData | string | ((row: TData, index: number) =&gt; string | number)</code></td><td>-</td><td>行唯一标识</td></tr><tr><td><code>selectable</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否启用选择列</td></tr><tr><td><code>sortable</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否启用排序交互</td></tr><tr><td><code>sorting</code></td><td><code>TableSortingState</code></td><td>-</td><td>受控排序状态</td></tr><tr><td><code>sortDescFirst</code></td><td><code>boolean</code></td><td><code>true</code></td><td>首次排序是否从降序开始</td></tr><tr><td><code>stripe</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否显示斑马纹</td></tr><tr><td><code>class</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>外层根节点 class，包含工具栏和表格</td></tr><tr><td><code>tableRootClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>表格根节点 class，仅作用于表格区域</td></tr><tr><td><code>tableClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>表格 class</td></tr><tr><td><code>headerClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>表头 class</td></tr><tr><td><code>headerRowClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>表头行 class</td></tr><tr><td><code>bodyClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>表体 class</td></tr><tr><td><code>rowClass</code></td><td><code>HTMLAttributes[&#39;class&#39;] | ((row: Row&lt;TData&gt;) =&gt; HTMLAttributes[&#39;class&#39;])</code></td><td>-</td><td>表格行 class</td></tr><tr><td><code>selectionColumnClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>选择列 class</td></tr><tr><td><code>tree</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否启用树型数据展示，展开图标渲染在首列</td></tr></tbody></table><h2 id="tablecolumn" tabindex="-1">TableColumn <a class="header-anchor" href="#tablecolumn" aria-label="Permalink to “TableColumn”">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>accessorKey</code></td><td><code>string</code></td><td>数据字段名</td></tr><tr><td><code>header</code></td><td><code>string | Function</code></td><td>表头内容</td></tr><tr><td><code>cell</code></td><td><code>string | Function</code></td><td>单元格内容</td></tr><tr><td><code>columns</code></td><td><code>TableColumn[]</code></td><td>多级表头子列</td></tr><tr><td><code>align</code></td><td><code>&#39;left&#39; | &#39;center&#39; | &#39;right&#39;</code></td><td>对齐方式</td></tr><tr><td><code>fixed</code></td><td><code>boolean | &#39;left&#39; | &#39;right&#39;</code></td><td>固定列位置</td></tr><tr><td><code>enableSorting</code></td><td><code>boolean</code></td><td>是否允许当前列排序</td></tr><tr><td><code>enableMultiSort</code></td><td><code>boolean</code></td><td>是否允许当前列参与多列排序</td></tr><tr><td><code>sortDescFirst</code></td><td><code>boolean</code></td><td>当前列首次排序是否从降序开始</td></tr><tr><td><code>sortingFn</code></td><td><code>string | Function</code></td><td>排序函数（组件内部不执行实际排序）</td></tr><tr><td><code>width</code></td><td><code>number | string</code></td><td>列宽</td></tr><tr><td><code>minWidth</code></td><td><code>number | string</code></td><td>最小列宽</td></tr><tr><td><code>maxWidth</code></td><td><code>number | string</code></td><td>最大列宽</td></tr><tr><td><code>class</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>列 class</td></tr><tr><td><code>headerClass</code></td><td><code>HTMLAttributes[&#39;class&#39;] | Function</code></td><td>表头 class</td></tr><tr><td><code>cellClass</code></td><td><code>HTMLAttributes[&#39;class&#39;] | Function</code></td><td>单元格 class</td></tr></tbody></table><p>选择列可配置 <code>{ type: &#39;selection&#39; }</code>，并可通过 <code>disabled</code> 控制某一行是否禁用选择。</p><p>排序能力基于 TanStack Table 的 <code>SortingState</code> 实现。开启 <code>sortable</code> 后，支持单列排序与 <code>Shift + 点击</code> 多列排序；组件只维护排序状态并触发事件，不会对传入数据做实际排序，当前参与排序的列会显示独立背景。</p><p>树型数据能力基于 TanStack Table 的 Expanding Row Model 实现。开启 <code>tree</code> 后，组件默认读取每行的 <code>children</code> 字段作为子行，也可以通过 <code>getSubRows</code> 自定义子行来源；展开图标固定渲染在首个可见列。</p><h2 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to “Slots”">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>说明</th><th>作用域参数</th></tr></thead><tbody><tr><td><code>caption</code></td><td>自定义表格标题</td><td>-</td></tr><tr><td><code>empty</code></td><td>自定义空状态</td><td><code>table</code></td></tr><tr><td><code>toolbar</code></td><td>自定义工具栏左侧内容</td><td><code>table</code></td></tr><tr><td><code>header-{columnId}</code></td><td>自定义指定列表头</td><td><code>column</code>、<code>header</code>、<code>table</code></td></tr><tr><td><code>cell-{columnId}</code></td><td>自定义指定列单元格</td><td><code>cell</code>、<code>column</code>、<code>index</code>、<code>row</code>、<code>table</code>、<code>value</code></td></tr><tr><td><code>footer-{columnId}</code></td><td>自定义指定列表尾</td><td><code>column</code>、<code>header</code>、<code>table</code></td></tr></tbody></table><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to “Events”">​</a></h2><table tabindex="0"><thead><tr><th>事件名</th><th>说明</th><th>回调参数</th></tr></thead><tbody><tr><td><code>row-click</code></td><td>点击表格行时触发</td><td><code>(row: TData, index: number, event: MouseEvent)</code></td></tr><tr><td><code>selection-change</code></td><td>选择状态变化时触发</td><td><code>(rows: TData[], rowSelection: RowSelectionState)</code></td></tr><tr><td><code>sorting-change</code></td><td>排序状态变化时触发</td><td><code>(sorting: TableSortingState, table: TanStackTable&lt;TData&gt;)</code></td></tr><tr><td><code>expanded-change</code></td><td>展开状态变化时触发</td><td><code>(expanded: TableExpandedState, table: TanStackTable&lt;TData&gt;)</code></td></tr><tr><td><code>update:expanded</code></td><td>受控展开状态更新时触发</td><td><code>(expanded: TableExpandedState)</code></td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li>推荐为复杂表格设置 <code>rowKey</code> 或 <code>getRowId</code>，保证选择状态和行更新稳定。</li><li>启用选择能力时需要设置 <code>selectable</code>，多选场景再配合 <code>multiple</code> 使用。</li><li>固定列建议显式设置列宽，避免横向滚动时出现宽度计算不稳定。</li><li>普通列默认可被列显示控制隐藏，设置 <code>enableHiding: false</code> 可禁止某列出现在列显示菜单中。</li><li>排序仅负责状态管理，真正的数据排序请在外部根据 <code>sorting-change</code> 自行处理。</li><li>树型数据建议设置 <code>rowKey</code> 或 <code>getRowId</code>，避免展开状态在数据更新后错位。</li></ol>',18)])])}const T=t(a,[["render",r]]);export{u as __pageData,T as default};
